&reftitle.description;
arrayfalseget_meta_tags stringfilename booluse_include_path&false;
Otwiera plik filename i analizuje go linia po linii w poszukiwaniu znaczników <meta>. Analiza kończy się na </head>.

  &reftitle.examples;



    Co zwraca get_meta_tags


<?php
// Zakładając, że powyższe znaczniki znajdują się pod adresem www.example.com
$tags = get_meta_tags('http://www.example.com/');

// Klucze są teraz pisane małymi literami, a kropka
// została zastąpiona znakiem _ w kluczu.
echo $tags['author'];       // name
echo $tags['keywords'];     // php documentation
echo $tags['description'];  // a php manual
echo $tags['geo_position']; // 49.33;-86.59
?>
